if (SolarSystem.getFlagPlanets()) {
    core.debug("Planets are visible");
} else {
    SolarSystem.setFlagPlanets(true);
}

// Hide all planets
SolarSystem.setFlagPlanets(false);

// Show all planets
SolarSystem.setFlagPlanets(true);

if (SolarSystem.getFlagHints()) {
    core.debug("Planet hints are visible");
}

if (SolarSystem.getFlagLabels()) {
    core.debug("Planet labels are visible");
}

// Show labels for bright planets only
SolarSystem.setLabelsAmount(2.0);

// Show labels for all planets
SolarSystem.setLabelsAmount(8.0);

if (SolarSystem.getFlagOrbits()) {
    core.debug("Planet orbits are visible");
}

if (SolarSystem.getFlagTrails()) {
    core.debug("Planet trails are visible");
}

if (SolarSystem.getFlagPointer()) {
    core.debug("Selection pointer is visible");
}

if (SolarSystem.getFlagMarkers()) {
    core.debug("Minor body markers are visible");
}

if (SolarSystem.getFlagLightTravelTime()) {
    core.debug("Light travel time correction is active");
}

// Reset trails to start fresh
SolarSystem.recreateTrails();
core.debug("Trails recreated");

// After editing ssystem_minor.ini
SolarSystem.reloadPlanets();
core.debug("Solar system data reloaded");

// Reset Mars texture
SolarSystem.resetTextures("Mars");

// Reset all planet textures
SolarSystem.resetTextures();

if (SolarSystem.getFlagMoonScale()) {
    core.debug("Moon is enlarged");
}

// Enlarge the Moon for better visibility
SolarSystem.setFlagMoonScale(true);
SolarSystem.setMoonScale(4.0);

// Make Moon 4 times larger
SolarSystem.setMoonScale(4.0);
SolarSystem.setFlagMoonScale(true);

if (SolarSystem.getFlagMinorBodyScale()) {
    core.debug("Minor bodies are enlarged");
}

// Enlarge minor bodies for visibility
SolarSystem.setFlagMinorBodyScale(true);
SolarSystem.setMinorBodyScale(10.0);

// Make asteroids 10 times larger
SolarSystem.setMinorBodyScale(10.0);
SolarSystem.setFlagMinorBodyScale(true);

if (SolarSystem.getFlagPlanetScale()) {
    core.debug("Planets are enlarged");
}

// Enlarge planets for visibility
SolarSystem.setFlagPlanetScale(true);
SolarSystem.setPlanetScale(150.0);

if (SolarSystem.getFlagSunScale()) {
    core.debug("Sun is enlarged");
}

// Enlarge the Sun
SolarSystem.setFlagSunScale(true);
SolarSystem.setSunScale(4.0);

if (SolarSystem.getFlagDrawMoonHalo()) {
    core.debug("Moon halo is visible");
}

if (SolarSystem.getFlagDrawSunHalo()) {
    core.debug("Sun halo is visible");
}

if (SolarSystem.getFlagIsolatedTrails()) {
    core.debug("Only selected objects show trails");
}

if (SolarSystem.getFlagIsolatedOrbits()) {
    core.debug("Only selected objects show orbits");
}

if (SolarSystem.getFlagPlanetsOrbits()) {
    core.debug("Major planet orbits are visible");
}

if (SolarSystem.getFlagPlanetsOrbitsOnly()) {
    core.debug("Only major planets show orbits");
}

if (SolarSystem.getFlagOrbitsWithMoons()) {
    core.debug("Moon orbits are visible");
}

// Show planet and moon orbits
SolarSystem.setFlagOrbitsWithMoons(true);
SolarSystem.setFlagOrbits(true);

if (SolarSystem.getFlagEphemerisMarkers()) {
    core.debug("Ephemeris markers are visible");
}

// Show planet position predictions
SolarSystem.setFlagEphemerisMarkers(true);
SolarSystem.setFlagEphemerisLine(true);

if (SolarSystem.getFlagEphemerisLine()) {
    core.debug("Ephemeris path line is visible");
}

if (SolarSystem.getFlagEphemerisDates()) {
    core.debug("Ephemeris dates are displayed");
}

if (SolarSystem.getFlagEphemerisMagnitudes()) {
    core.debug("Ephemeris magnitudes are displayed");
}

if (SolarSystem.getFlagEphemerisAlwaysOn()) {
    core.debug("Ephemeris markers always visible");
}

if (SolarSystem.getFlagEphemerisNow()) {
    core.debug("Current position marker is visible");
}

if (SolarSystem.getFlagEphemerisHorizontalCoordinates()) {
    core.debug("Ephemeris in Alt/Az coordinates");
}

if (SolarSystem.getFlagEphemerisSmartDates()) {
    core.debug("Smart date formatting is active");
}

if (SolarSystem.getFlagEphemerisFirstOfMonthOnly()) {
    core.debug("Only month boundaries are labeled");
}

// Read the color (returns a string like '1.0,0.0,0.0')
var labelColorStr = core.getStelProperty('SolarSystem.labelsColor');
var parts = labelColorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);
core.debug("Labels color RGB: " + r.toFixed(2) + ", " + g.toFixed(2) + ", " + b.toFixed(2));

// Set labels to white
var white = core.vec3f(1.0, 1.0, 1.0);
SolarSystem.setLabelsColor(white);

// Set labels to light blue
var lightBlue = core.vec3f(0.5, 0.7, 1.0);
SolarSystem.setLabelsColor(lightBlue);

// Read the pointer color
var pointerColorStr = core.getStelProperty('SolarSystem.pointerColor');
var parts = pointerColorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);
core.debug("Pointer color RGB: " + r.toFixed(2) + ", " + g.toFixed(2) + ", " + b.toFixed(2));

var trailsColorStr = core.getStelProperty('SolarSystem.trailsColor');
var parts = trailsColorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);

// Set orbits to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
SolarSystem.setOrbitsColor(cyan);

// Get all solar system objects
var allObjects = SolarSystem.getObjectsList("all");

// Get only asteroids
var asteroids = SolarSystem.getObjectsList("asteroid");

core.debug("Asteroids count: " + asteroids.length);

var sun = SolarSystem.getSun();
var sunRadiusKm = sun.getEquatorialRadius() * 149597870.7;
core.debug("Sun radius: " + sunRadiusKm.toFixed(0) + " km");

// Remove a test asteroid
if (SolarSystem.removeMinorPlanet("99942 Apophis")) {
    core.debug("Apophis removed.");
}
